mapper.select:
SELECT id, user_id, user_name, user_phone, complaint_title, complaint_content, complaint_type, complaint_status, handle_user_id, handle_user_name, handle_result, handle_time, create_by, create_time, update_by, update_time, remark
FROM community_complaint

    and user_name LIKE CONCAT('%', #{userName}, '%')
    and user_phone = #{userPhone}
    and complaint_title LIKE CONCAT('%', #{complaintTitle}, '%')
    and complaint_content LIKE CONCAT('%', #{complaintContent}, '%')
    and complaint_type = #{complaintType}
    and complaint_status = #{complaintStatus}
    and handle_user_id = #{handleUserId}
    and handle_user_name LIKE CONCAT('%', #{handleUserName}, '%')
    and handle_result = #{handleResult}
    and handle_time = #{handleTime}

order by create_time desc

SELECT id, user_id, user_name, user_phone, complaint_title, complaint_content, complaint_type, complaint_status, handle_user_id, handle_user_name, handle_result, handle_time, create_by, create_time, update_by, update_time, remark
FROM community_complaint
WHERE id = #{id}
